SELECT study_id, MAX(withdrawal_date) 
FROM study_subjects 
GROUP BY study_id;

SELECT study_id, COUNT(*)
FROM experimental_conditions
GROUP BY study_id;

SELECT AVG(age_at_sacrifice)
FROM subjects
WHERE sac_date > (SELECT start_date FROM studies WHERE study_id = 1);

SELECT DISTINCT subject_id
FROM study_subjects
WHERE study_id = 1;

SELECT condition_name 
FROM experimental_conditions 
WHERE study_id = 1;
